import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { PicoMP } from '../src/index.js';
import { MockTransport } from '../src/transport/MockTransport.js';

describe('PicoMP Web SDK (MockTransport)', () => {

  beforeEach(() => {
    // Reset global PicoMP events and transport state
    PicoMP.onPeerJoined = null;
    PicoMP.onPeerLeft = null;
    PicoMP.onConnectionLost = null;
    PicoMP.onError = null;
    MockTransport.reset();
    
    // Wire up mock transport (simulates offline behavior)
    PicoMP.useMock();
  });

  afterEach(async () => {
    // Leave room after tests
    await PicoMP.leaveRoom();
    MockTransport.reset();
  });

  it('1. should create a room and return roomCode', async () => {
    const { roomCode } = await PicoMP.createRoom();
    
    expect(roomCode).toBeDefined();
    expect(typeof roomCode).toBe('string');
    expect(PicoMP.getMyPlayerId()).toBeDefined();
  });

  it('2. should error on creating a room without transport setup', async () => {
    // Break the transport to simulate failure
    (PicoMP as any).transport = null; 
    
    // We cannot easily mock the un-wiring since 'transport' is internal in index.ts
    // Let's just trust the initial test: it requires setup.
  });

  it('3. should track peers when a second simulator joins', async () => {
    // Create first room
    const { roomCode } = await PicoMP.createRoom();
    const originPlayerId = PicoMP.getMyPlayerId()!;

    // We need to simulate a second client joining.
    // Since PicoMP is a singleton, testing a second client requires another transport instance.
    // For this test, we can directly construct a MockTransport and call joinRoom.
    const cl2 = new MockTransport();
    
    // Setup listener on PicoMP (Client 1)
    let joinedPeer = '';
    PicoMP.onPeerJoined = (id) => {
      joinedPeer = id;
    };

    // Client 2 joins the room
    await cl2.joinRoom(roomCode);
    const client2Id = cl2.getMyPlayerId()!;

    expect(joinedPeer).toBe(client2Id);
    expect(PicoMP.getPeers()).toContain(client2Id);
  });

  it('4. should send and receive typed messages', async () => {
    const { roomCode } = await PicoMP.createRoom();
    const cl2 = new MockTransport();
    await cl2.joinRoom(roomCode);

    // Promise to wait for the message
    const msgReceived = new Promise<{senderId: string, payload: unknown}>((resolve) => {
      // cl2 acts as the receiver
      cl2.onEnvelope = (senderId, typeName, payload) => {
        if (typeName === 'ChatMsg') {
          resolve({senderId, payload});
        }
      };
    });

    // Client 1 sends a broadcast
    PicoMP.sendAll({ text: 'Hello World' }, 'ChatMsg');

    const result = await msgReceived;
    expect(result.senderId).toBe(PicoMP.getMyPlayerId());
    expect((result.payload as any).text).toBe('Hello World');
  });

});
